CREATE TABLE COTIZACIONES (MONEDA VARCHAR(3) PRIMARY KEY, TASA_CAMBIO FLOAT NOT NULL);
CREATE TABLE TARJETAS (ID BIGINT AUTO_INCREMENT PRIMARY KEY, NUMERO VARCHAR(16) NOT NULL UNIQUE, TITULAR VARCHAR(100) NOT NULL, LIMITE_CREDITO FLOAT NOT NULL);
CREATE TABLE CONSUMOS (ID BIGINT AUTO_INCREMENT PRIMARY KEY, ID_TARJETA BIGINT NOT NULL, MONTO FLOAT NOT NULL, DIA INT NOT NULL, MES INT NOT NULL, ANIO INT NOT NULL, RUBRO VARCHAR(20) NOT NULL, MONEDA VARCHAR(3) NOT NULL, CONSTRAINT fk_consumo_tarjeta FOREIGN KEY (ID_TARJETA) REFERENCES TARJETAS(ID));
CREATE TABLE LIQUIDACIONES (ID BIGINT AUTO_INCREMENT PRIMARY KEY, ID_TARJETA BIGINT NOT NULL, MES INT NOT NULL, ANIO INT NOT NULL, TOTAL_A_PAGAR FLOAT NOT NULL, TOTAL_CONSUMOS FLOAT NOT NULL, TOTAL_IMPUESTOS FLOAT NOT NULL, TOTAL_DESCUENTOS FLOAT NOT NULL, CONSTRAINT fk_liquidacion_tarjeta FOREIGN KEY (ID_TARJETA) REFERENCES TARJETAS(ID));